/**
 * @fileoverview GridTable Feature — Selection (checkbox) mixin.
 *
 * Lazy-loaded when `showCheckbox: true` is set in config.
 * Adds row selection via checkboxes with select-all toggle.
 *
 * @module module/GridTable/features/selection
 */

import { bindRowEvents } from '../events.js';

/**
 * Install the selection feature onto a GridTable ctx bridge.
 *
 * @param {object} ctx — the shared context bridge
 */
export function installSelection(ctx) {
    ctx._selectionInstalled = true;

    /**
     * Toggle select-all / deselect-all.
     */
    ctx.toggleSelectAll = () => {
        const total = ctx._getDisplayCount();
        if (ctx.selectedRows.size >= total) {
            ctx.selectedRows.clear();
        } else {
            for (let i = 0; i < total; i++) ctx.selectedRows.add(i);
        }
        ctx.scheduleRender(true);
    };

    /**
     * Get the set of selected row display indices.
     * @returns {Set<number>}
     */
    ctx.getSelectedRows = () => new Set(ctx.selectedRows);
}

export default installSelection;
